// Código para usar no node "Code" do n8n
// Configure o node para "Run Once for Each Item"

const data = $input.item.json;

try {
  // Verifica se o campo keywords existe e é uma string
  if (data.keywords && typeof data.keywords === 'string') {
    // Remove espaços em branco no início e fim
    let keywordsString = data.keywords.trim();

    // Solução robusta para converter Python dict string para JSON válido
    // Esta regex substitui aspas simples por duplas, exceto quando estão dentro de valores de string
    keywordsString = keywordsString.replace(/'/g, (match, offset, string) => {
      // Verifica se a aspa está dentro de um valor (entre : e , ou : e })
      const beforeColon = string.lastIndexOf(':', offset);
      const beforeComma = string.lastIndexOf(',', offset);
      const beforeBrace = string.lastIndexOf('{', offset);

      const afterColon = string.indexOf(':', offset);
      const afterComma = string.indexOf(',', offset);
      const afterBrace = string.indexOf('}', offset);

      // Se estamos dentro de um valor (depois de : e antes de , ou })
      const startOfValue = Math.max(beforeColon, beforeComma, beforeBrace);
      const endOfValue = Math.min(
        afterComma === -1 ? Infinity : afterComma,
        afterBrace === -1 ? Infinity : afterBrace
      );

      // Se a posição atual está entre : e , (ou }), pode ser uma aspa dentro do valor
      if (beforeColon > beforeComma && beforeColon > beforeBrace && 
          (afterComma > offset || afterBrace > offset)) {

        // Verifica se é uma contração (letra antes e depois da aspa)
        const charBefore = string[offset - 1];
        const charAfter = string[offset + 1];

        if (/[a-zA-Z]/.test(charBefore) && /[a-zA-Z]/.test(charAfter)) {
          return '\\"'; // Escapa a aspa se for uma contração
        }
      }

      return '"'; // Substitui por aspa dupla nos outros casos
    });

    // Tenta fazer o parse
    let keywordsArray;
    try {
      keywordsArray = JSON.parse(keywordsString);
    } catch (firstError) {
      // Se falhou, tenta uma abordagem mais agressiva
      keywordsString = data.keywords.trim();

      // Método alternativo: usando eval com segurança limitada
      // Substitui apenas as estruturas específicas
      keywordsString = keywordsString
        .replace(/'/g, '"')  // Troca aspas simples por duplas
        .replace(/(\w)\"(\w)/g, '$1\'$2')  // Volta aspas simples dentro de palavras
        .replace(/\"\s*:\s*\"/g, '": "')  // Garante espaçamento correto
        .replace(/\"\s*,\s*\"/g, '", "'); // Garante espaçamento correto

      try {
        keywordsArray = JSON.parse(keywordsString);
      } catch (secondError) {
        // Última tentativa: limpar caracteres problemáticos
        keywordsString = data.keywords.trim()
          .replace(/'/g, '"')
          .replace(/(\w)"(\w)/g, '$1&apos;$2')  // Substitui temporariamente
          .replace(/&apos;/g, "'");  // Volta como aspa simples

        keywordsArray = JSON.parse(keywordsString);
      }
    }

    // Atualiza o campo keywords no objeto
    data.keywords = keywordsArray;
  }

  return data;

} catch (error) {
  // Em caso de erro, retorna o item original com informação do erro
  console.error(`Erro ao processar item com ID ${data.id}:`, error.message);

  return {
    ...data,
    error: `Erro ao converter keywords: ${error.message}`
  };
}
